                callWaiting.userId.ne(excludeUserId),
                userProfile.gender.ne(myGender),
                callPreference.ageMin.loe(myAge),
                callPreference.ageMax.goe(myAge)
            )
            .orderBy(callWaiting.waitingSince.asc()) // 오래 기다린 사람 우선
            .limit(20) // 후보군 제한
            .fetch()
    }
}
```

예상 효과: 201개 쿼리 -> 1개 쿼리. 응답 시간 500ms -> 30ms (94% 개선).

