### 최적화 4: 매칭 완료 처리 비동기화

```kotlin
// AFTER: 비동기 코루틴으로 병렬 처리
// CallMatchingService.kt

@Service
class CallMatchingService(
    private val matchingRepository: CallMatchingRepository,
    private val redisRepository: CallMatchingRedisRepository,
    private val pushNotificationClient: PushNotificationGrpcClient,
    private val callRoomClient: CallRoomGrpcClient,
    private val applicationEventPublisher: ApplicationEventPublisher
) {
    @Transactional
    suspend fun completeMatching(matchId: String, userId1: String, userId2: String) {
        // 1. DB 상태 업데이트 (동기 필수)
        matchingRepository.updateStatus(matchId, MatchingStatus.COMPLETED)

        // 2. Redis 대기 풀에서 즉시 제거 (동기 필수 - 중복 매칭 방지)
        redisRepository.removeFromWaitingPool(userId1)
        redisRepository.removeFromWaitingPool(userId2)

        // 3. 나머지 처리는 이벤트로 비동기 처리
        applicationEventPublisher.publishEvent(
            MatchingCompletedEvent(matchId, userId1, userId2)
        )
    }
}

// 비동기 이벤트 핸들러
@Component
class MatchingCompletedEventHandler(
    private val pushNotificationClient: PushNotificationGrpcClient,
    private val callRoomClient: CallRoomGrpcClient,
    private val matchingHistoryRepository: CallMatchingHistoryRepository
) {
    @Async("matchingTaskExecutor")
    @TransactionalEventListener(phase = TransactionPhase.AFTER_COMMIT)
    fun handle(event: MatchingCompletedEvent) = runBlocking {
        // 병렬 실행
        val pushJob1 = async { pushNotificationClient.send(event.userId1) }
        val pushJob2 = async { pushNotificationClient.send(event.userId2) }
        val roomJob = async { callRoomClient.createRoom(event.matchId) }

        awaitAll(pushJob1, pushJob2, roomJob) // 모두 완료 대기 (~300ms)

        matchingHistoryRepository.save(
            CallMatchingHistory(matchId = event.matchId, completedAt = LocalDateTime.now())
        )
    }
}

// ThreadPoolTaskExecutor 설정
@Configuration
class AsyncConfig {
    @Bean("matchingTaskExecutor")
    fun matchingTaskExecutor(): Executor = ThreadPoolTaskExecutor().apply {
        corePoolSize = 5
        maxPoolSize = 20
        queueCapacity = 100
        setThreadNamePrefix("matching-async-")
        initialize()
    }
}
```

예상 효과: 직렬 900ms -> 비동기 응답 10ms (API 응답), 백그라운드 처리 300ms.

